import java.io.*;
import java.util.*;

public class Main {
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && Character.isWhitespace(c)) {}
            if (c == -1) return null;
            do {
                sb.append((char) c);
                c = readByte();
            } while (c != -1 && !Character.isWhitespace(c));
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
    }
    static class Node {
        int val;
        Node left, right;
        Node(int v) { this.val = v; }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        String token = fs.next();
        if (token == null) return;
        int T = Integer.parseInt(token);
        for (int tc = 0; tc < T; tc++) {
            int N = fs.nextInt();
            if (N == 1) {
                // For a single node tree, the node value is assumed to be 1 (as per problem examples)
                out.append("1\n");
                continue;
            }
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> childSet = new HashSet<>();
            for (int i = 0; i < N - 1; i++) {
                int p = fs.nextInt();
                int c = fs.nextInt();
                String posStr = fs.next();
                char pos = posStr.charAt(0);
                Node parent = map.computeIfAbsent(p, k -> new Node(k));
                Node child = map.computeIfAbsent(c, k -> new Node(k));
                if (pos == 'L') parent.left = child; else parent.right = child;
                childSet.add(c);
            }
            Node root = null;
            for (int key : map.keySet()) {
                if (!childSet.contains(key)) { root = map.get(key); break; }
            }
            if (root == null) root = map.values().iterator().next();
            Deque<Node> dq = new ArrayDeque<>();
            dq.add(root);
            boolean leftToRight = true;
            while (!dq.isEmpty()) {
                int sz = dq.size();
                int[] level = new int[sz];
                for (int i = 0; i < sz; i++) {
                    Node cur = dq.pollFirst();
                    int idx = leftToRight ? i : sz - 1 - i;
                    level[idx] = cur.val;
                    if (cur.left != null) dq.addLast(cur.left);
                    if (cur.right != null) dq.addLast(cur.right);
                }
                for (int i = 0; i < sz; i++) {
                    if (i > 0) out.append(' ');
                    out.append(level[i]);
                }
                out.append('\n');
                leftToRight = !leftToRight;
            }
        }
        System.out.print(out.toString());
    }
}

